import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line } from 'recharts';
import { TrendingUp, TrendingDown, Calendar, Users, CreditCard, Target, ArrowUp, ArrowDown, Minus } from 'lucide-react';
import Card from './Card';

const METRICS = [
  { key: 'registered_onboarded', label: 'Registered Onboarded', icon: Users, color: '#3B82F6' },
  { key: 'linked_accounts', label: 'Linked Accounts', icon: CreditCard, color: '#10B981' },
  { key: 'total_advance_applications', label: 'Total Advance Applications', icon: Target, color: '#F59E0B' },
  { key: 'total_advance_applicants', label: 'Total Advance Applicants', icon: Users, color: '#8B5CF6' },
  { key: 'total_micro_financing_applications', label: 'Total Micro Financing Applications', icon: Target, color: '#EF4444' },
  { key: 'total_micro_financing_applicants', label: 'Total Micro Financing Applicants', icon: Users, color: '#06B6D4' },
  { key: 'total_personal_finance_application', label: 'Total Personal Finance Applications', icon: Target, color: '#84CC16' },
  { key: 'total_personal_finance_applicants', label: 'Total Personal Finance Applicants', icon: Users, color: '#F97316' }
];

// Analytics API calls
const analyticsApi = {
  getMonthlyComparison: async (params: any) => {
    const searchParams = new URLSearchParams();
    if (params.weeks) searchParams.append('weeks', params.weeks);
    if (params.months) searchParams.append('months', params.months);
    if (params.metric) searchParams.append('metric', params.metric);
    
    const response = await fetch(`/api/analytics/monthly-comparison?${searchParams}`);
    if (!response.ok) throw new Error('Failed to fetch monthly comparison');
    return response.json();
  }
};

const MonthlyComparison: React.FC = () => {
  const [selectedWeeks, setSelectedWeeks] = useState(['all']);
  const [selectedMonths, setSelectedMonths] = useState<string[]>([]);
  const [selectedMetric, setSelectedMetric] = useState('total_advance_applicants');
  const [selectAllMonths, setSelectAllMonths] = useState(true);
  const [chartType, setChartType] = useState<'bar' | 'line'>('bar');

  const { data, isLoading, error } = useQuery({
    queryKey: ['monthly-comparison', selectedWeeks, selectedMonths, selectedMetric],
    queryFn: () => analyticsApi.getMonthlyComparison({
      weeks: selectedWeeks.includes('all') ? 'all' : selectedWeeks.join(','),
      months: selectAllMonths ? undefined : selectedMonths.join(','),
      metric: selectedMetric
    })
  });

  const handleWeekToggle = (week: string) => {
    if (week === 'all') {
      setSelectedWeeks(['all']);
    } else {
      setSelectedWeeks(prev => {
        const newWeeks = prev.filter(w => w !== 'all');
        if (newWeeks.includes(week)) {
          const filtered = newWeeks.filter(w => w !== week);
          return filtered.length === 0 ? ['all'] : filtered;
        } else {
          return [...newWeeks, week];
        }
      });
    }
  };

  const handleMonthToggle = (month: string) => {
    setSelectedMonths(prev => {
      if (prev.includes(month)) {
        return prev.filter(m => m !== month);
      } else {
        return [...prev, month];
      }
    });
  };

  const handleSelectAllMonths = () => {
    setSelectAllMonths(!selectAllMonths);
    if (!selectAllMonths) {
      setSelectedMonths([]);
    }
  };

  const availableMonths = data?.rows?.map((r: any) => r.month) || [];
  
  // Calculate KPIs
  const totalValue = data?.rows?.reduce((sum: number, row: any) => sum + row.value, 0) || 0;
  const avgValue = data?.rows?.length ? totalValue / data.rows.length : 0;
  const bestMonth = data?.rows?.reduce((best: any, row: any) => row.value > (best?.value || 0) ? row : best, null);
  const worstMonth = data?.rows?.reduce((worst: any, row: any) => row.value < (worst?.value || Infinity) ? row : worst, null);
  
  // Calculate trend
  const recentChanges = data?.mom_changes?.slice(-3) || [];
  const avgChange = recentChanges.length ? recentChanges.reduce((sum: number, change: any) => sum + change.pct, 0) / recentChanges.length : 0;
  
  const selectedMetricData = METRICS.find(m => m.key === selectedMetric);

  const formatValue = (value: number) => {
    if (value >= 1000000) return (value / 1000000).toFixed(1) + 'M';
    if (value >= 1000) return (value / 1000).toFixed(1) + 'K';
    return value.toLocaleString();
  };

  const getTrendIcon = (change: number) => {
    if (change > 5) return <ArrowUp className="h-4 w-4 text-green-600" />;
    if (change < -5) return <ArrowDown className="h-4 w-4 text-red-600" />;
    return <Minus className="h-4 w-4 text-gray-600" />;
  };

  const getTrendColor = (change: number) => {
    if (change > 5) return 'text-green-600';
    if (change < -5) return 'text-red-600';
    return 'text-gray-600';
  };

  return (
    <Card title="Monthly Comparison">
      <div className="space-y-6">
        {/* Metric Selector */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Select Metric
          </label>
          <select
            value={selectedMetric}
            onChange={(e) => setSelectedMetric(e.target.value)}
            className="w-full p-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500"
          >
            {METRICS.map(metric => (
              <option key={metric.key} value={metric.key}>
                {metric.label}
              </option>
            ))}
          </select>
        </div>

        {/* Week Pills */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Select Weeks
          </label>
          <div className="flex flex-wrap gap-2">
            {['all', '1', '2', '3', '4', '5'].map(week => (
              <button
                key={week}
                onClick={() => handleWeekToggle(week)}
                className={`px-3 py-1 rounded-full text-sm font-medium transition-colors ${
                  selectedWeeks.includes(week)
                    ? 'bg-blue-500 text-white'
                    : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
                }`}
              >
                {week === 'all' ? 'All Weeks' : `Week ${week}`}
              </button>
            ))}
          </div>
        </div>

        {/* Month Selection */}
        <div>
          <div className="flex items-center justify-between mb-2">
            <label className="block text-sm font-medium text-gray-700">
              Select Months to Compare
            </label>
            <button
              onClick={handleSelectAllMonths}
              className="text-sm text-blue-600 hover:text-blue-800"
            >
              {selectAllMonths ? 'Select Specific' : 'Select All'}
            </button>
          </div>
          
          {!selectAllMonths && (
            <div className="grid grid-cols-3 gap-2 max-h-32 overflow-y-auto border rounded-md p-3">
              {availableMonths.map((month: string) => (
                <label key={month} className="flex items-center space-x-2">
                  <input
                    type="checkbox"
                    checked={selectedMonths.includes(month)}
                    onChange={() => handleMonthToggle(month)}
                    className="w-4 h-4 text-blue-600"
                  />
                  <span className="text-sm">{month}</span>
                </label>
              ))}
            </div>
          )}
        </div>

        {/* Results */}
        {isLoading && (
          <div className="flex justify-center py-8">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-500"></div>
          </div>
        )}

        {error && (
          <div className="bg-red-50 border border-red-200 rounded-md p-4">
            <p className="text-red-800">Error loading data: {(error as Error)?.message || 'Unknown error'}</p>
          </div>
        )}

        {data && data.rows && data.rows.length > 0 ? (
          <div className="space-y-4">
            {/* Chart */}
            <div className="h-64">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={data.rows}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="month" />
                  <YAxis />
                  <Tooltip />
                  <Bar dataKey="value" fill="#3B82F6" />
                </BarChart>
              </ResponsiveContainer>
            </div>

            {/* Data Table */}
            <div className="overflow-x-auto">
              <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Month
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Value
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      Days Counted
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                      MoM Change
                    </th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {data.rows.map((row: any, index: number) => {
                    const momChange = data.mom_changes?.find((change: any) => change.to === row.month);
                    return (
                      <tr key={row.month}>
                        <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                          {row.month}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                          {row.value.toLocaleString()}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                          {row.daysCounted}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm">
                          {momChange ? (
                            <span className={`font-medium ${momChange.pct >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                              {momChange.pct >= 0 ? '+' : ''}{momChange.pct}%
                            </span>
                          ) : (
                            <span className="text-gray-400">—</span>
                          )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>

            {/* Footer Info */}
            <div className="text-sm text-gray-600 bg-gray-50 p-3 rounded-md">
              <p>
                <strong>Time Selection:</strong> {selectedWeeks.includes('all') ? 'All Weeks' : `Week ${selectedWeeks.join(', ')}`}, All Days
              </p>
              <p>
                <strong>Months Selected:</strong> {selectAllMonths ? 'All Available' : (selectedMonths.length === 0 ? 'None' : selectedMonths.join(', '))}
              </p>
            </div>
          </div>
        ) : (
          !isLoading && (
            <div className="text-center py-8">
              <p className="text-gray-500 mb-4">No data available for the selected criteria</p>
              <button className="bg-blue-500 text-white px-4 py-2 rounded-md hover:bg-blue-600">
                Go to Data Entry
              </button>
            </div>
          )
        )}
      </div>
    </Card>
  );
};

export default MonthlyComparison;
